export type NonPostableEvt<T> = {
    waitFor: () => Promise<T>;
    subscribe: (next: (data: T) => void) => {
        unsubscribe: () => void;
    };
    postCount: number;
};
export type Evt<T> = NonPostableEvt<T> & {
    post: (data: T) => void;
};
export declare function createEvt<T>(): Evt<T>;
